solution_code:
#include <iostream>
#include <string>
#include <vector>

constexpr double pi{ 3.14159265 };

class Shape
{
public:
    virtual double area() const { return 0.0; }
};

class Circle : public Shape
{
    int m_radius{};

public:
    Circle(int radius)
        : m_radius{ radius }
    {
    }

    double area() const { return pi * m_radius * m_radius; }
};

class Rectangle : public Shape
{
    int m_width{};
    int m_height{};

public:
    Rectangle(int width, int height)
        : m_width{ width }
        , m_height{ height }
    {
    }

    double area() const { return static_cast<double>(m_width) * m_height; }
};

class Triangle : public Shape
{
    int m_base{};
    int m_height{};

public:
    Triangle(int base, int height)
        : m_base{ base }
        , m_height{ height }
    {
    }

    double area() const { return 0.5 * m_base * m_height; }
};

int main()
{
    int n{};
    std::cin >> n;

    std::vector<Shape*> shapes{};
    for (int i{ 0 }; i < n; ++i)
    {
        std::string type{};
        std::cin >> type;
        if (type == "circle")
        {
            int r{};
            std::cin >> r;
            shapes.push_back(new Circle{ r });
        }
        else if (type == "rect")
        {
            int w{}, h{};
            std::cin >> w >> h;
            shapes.push_back(new Rectangle{ w, h });
        }
        else
        {
            int b{}, h{};
            std::cin >> b >> h;
            shapes.push_back(new Triangle{ b, h });
        }
    }

    double total{ 0.0 };
    double largest{ 0.0 };
    for (const Shape* s : shapes)
    {
        double a{ s->area() };
        total += a;
        if (a > largest)
            largest = a;
    }

    std::cout << "Total: " << static_cast<int>(total) << '\n';
    std::cout << "Largest: " << static_cast<int>(largest) << '\n';

    for (Shape* s : shapes)
        delete s;

    return 0;
}
